import { isEqual } from '@ember/utils';
import type EmberArrayLike from '@ember/array';
import type {
  DefaultHighlightedParams,
  GroupBase,
  MatcherFn,
  Option,
  Selected,
} from '../types';

export function isGroup<T>(entry: unknown): entry is GroupBase<T> {
  return (
    !!entry &&
    typeof entry === 'object' &&
    'groupName' in entry &&
    'options' in entry &&
    !!entry.groupName &&
    !!entry.options
  );
}

export function countOptions<T = unknown>(collection: readonly T[]): number {
  let counter = 0;
  (function walk(collection): void {
    if (!collection) {
      return;
    }
    for (let i = 0; i < collection.length; i++) {
      const entry =
        collection &&
        'objectAt' in collection &&
        typeof collection.objectAt === 'function'
          ? (collection as unknown as EmberArrayLike<T>).objectAt(i)
          : collection[i];
      if (isGroup(entry)) {
        walk((entry as unknown as GroupBase<T>).options);
      } else {
        counter++;
      }
    }
  })(collection);
  return counter;
}

export function indexOfOption<T, Option, IsMultiple extends boolean = false>(
  collection: readonly T[],
  option: Option,
): number {
  let index = 0;
  return (function walk(collection): number {
    if (!collection) {
      return -1;
    }
    for (let i = 0; i < collection.length; i++) {
      const entry =
        collection &&
        'objectAt' in collection &&
        typeof collection.objectAt === 'function'
          ? (
              collection as unknown as EmberArrayLike<Selected<T, IsMultiple>>
            ).objectAt(i)
          : collection[i];
      if (isGroup(entry)) {
        const result = walk((entry as unknown as GroupBase<T>).options);
        if (result > -1) {
          return result;
        }
      } else if (isEqual(entry, option)) {
        return index;
      } else {
        index++;
      }
    }
    return -1;
  })(collection);
}

export function pathForOption<T = unknown>(
  collection: readonly T[],
  option: unknown,
): string {
  return (function walk(collection): string {
    if (!collection) {
      return '';
    }
    for (let i = 0; i < collection.length; i++) {
      const entry =
        collection &&
        'objectAt' in collection &&
        typeof collection.objectAt === 'function'
          ? (collection as unknown as EmberArrayLike<T>).objectAt(i)
          : collection[i];
      if (isGroup(entry)) {
        const result = walk((entry as unknown as GroupBase<T>).options);
        if (result.length > 0) {
          return i + '.' + result;
        }
      } else if (isEqual(entry, option)) {
        return i + '';
      }
    }
    return '';
  })(collection);
}

export function optionAtIndex<T>(
  originalCollection: readonly T[],
  index: number,
): { disabled: boolean; option: Option<T> | undefined } {
  let counter = 0;
  return (
    (function walk(
      collection,
      ancestorIsDisabled,
    ): { disabled: boolean; option: Option<T> | undefined } | void {
      if (!collection || index < 0) {
        return { disabled: false, option: undefined };
      }
      let localCounter = 0;
      const length = collection.length;
      while (counter <= index && localCounter < length) {
        const entry =
          collection &&
          'objectAt' in collection &&
          typeof collection.objectAt === 'function'
            ? (collection as unknown as EmberArrayLike<T>).objectAt(
                localCounter,
              )
            : collection[localCounter];
        if (isGroup(entry)) {
          const found = walk(
            (entry as unknown as GroupBase<T>).options,
            ancestorIsDisabled || !!(entry as unknown as GroupBase<T>).disabled,
          );
          if (found) {
            return found;
          }
        } else if (counter === index) {
          return {
            disabled:
              ancestorIsDisabled ||
              !!(entry as unknown as GroupBase<T>).disabled,
            option: entry as Option<T>,
          };
        } else {
          counter++;
        }
        localCounter++;
      }
    })(originalCollection, false) || { disabled: false, option: undefined }
  );
}

function copyGroup<T = unknown, IsMultiple extends boolean = false>(
  group: GroupBase<Selected<T, IsMultiple>>,
  subOptions: Selected<T, IsMultiple>[],
): GroupBase<Selected<T, IsMultiple>> {
  const groupCopy: GroupBase<Selected<T, IsMultiple>> = {
    ...group,
    options: subOptions,
  };
  if (Object.prototype.hasOwnProperty.call(group, 'disabled')) {
    groupCopy.disabled = group.disabled;
  }
  return groupCopy;
}

export function findOptionWithOffset<T>(
  options: readonly T[],
  text: string,
  matcher: MatcherFn<T>,
  offset: number,
  skipDisabled = false,
): Option<T> | undefined {
  let counter = 0;
  let foundBeforeOffset: Option<T> | undefined;
  let foundAfterOffset: Option<T> | undefined | false = false;
  const canStop = () => !!foundAfterOffset;

  (function walk(options: readonly T[], ancestorIsDisabled: boolean): void {
    const length = options.length;

    for (let i = 0; i < length; i++) {
      const entry =
        options &&
        'objectAt' in options &&
        typeof options.objectAt === 'function'
          ? (options as unknown as EmberArrayLike<T>).objectAt(i)
          : options[i];
      const entryIsDisabled =
        !!entry &&
        typeof entry === 'object' &&
        'disabled' in entry &&
        !!entry.disabled;
      if (!skipDisabled || !entryIsDisabled) {
        if (isGroup(entry)) {
          walk(
            (entry as unknown as GroupBase<T>).options,
            ancestorIsDisabled || entryIsDisabled,
          );
          if (canStop()) {
            return;
          }
        } else if (matcher(entry, text) >= 0) {
          if (counter < offset) {
            if (!foundBeforeOffset) {
              foundBeforeOffset = entry as Option<T>;
            }
          } else {
            foundAfterOffset = entry as Option<T>;
          }
          counter++;
        } else {
          counter++;
        }

        if (canStop()) {
          return;
        }
      }
    }
  })(options, false);

  return foundAfterOffset ? foundAfterOffset : foundBeforeOffset;
}

export function filterOptions<
  T = unknown,
  MT = unknown,
  IsMultiple extends boolean = false,
>(
  options: readonly T[],
  text: string,
  matcher: MatcherFn<MT>,
  skipDisabled = false,
): T[] {
  const opts: T[] = [];
  const length = options.length;
  for (let i = 0; i < length; i++) {
    const entry =
      options && 'objectAt' in options && typeof options.objectAt === 'function'
        ? (options as unknown as EmberArrayLike<T>).objectAt(i)
        : options[i];
    if (
      !skipDisabled ||
      !(
        entry &&
        typeof entry === 'object' &&
        'disabled' in entry &&
        entry.disabled
      )
    ) {
      if (isGroup(entry)) {
        const suboptions = filterOptions(
          (entry as unknown as GroupBase<Selected<T, IsMultiple>>).options,
          text,
          matcher,
          skipDisabled,
        );
        if (suboptions.length > 0) {
          opts.push(
            copyGroup(
              entry as GroupBase<Selected<T, IsMultiple>>,
              suboptions,
            ) as T,
          );
        }
      } else if (entry && matcher(entry as MT, text) >= 0) {
        opts.push(entry);
      }
    }
  }
  return opts;
}

export function defaultHighlighted<T>({
  results,
  highlighted,
  selected,
}: DefaultHighlightedParams<T>): Option<T> | undefined {
  let option: Option<T> | undefined = highlighted;

  if (!option) {
    if (Array.isArray(selected)) {
      option = undefined; // Maybe correct is selected[0], but tests do fail right now
    } else {
      option = selected;
    }
  }

  if (option === undefined || indexOfOption(results, option) === -1) {
    return advanceSelectableOption(results, option, 1);
  }
  return option;
}

export function advanceSelectableOption<T, IsMultiple extends boolean = false>(
  options: readonly T[],
  currentOption: Selected<T, IsMultiple>,
  step: 1 | -1,
): Option<T> | undefined {
  const resultsLength = countOptions(options);
  let startIndex = Math.min(
    Math.max(indexOfOption(options, currentOption) + step, 0),
    resultsLength - 1,
  );
  let { disabled, option } = optionAtIndex(options, startIndex);
  while (option && disabled) {
    const next = optionAtIndex(options, (startIndex += step));
    disabled = next.disabled;
    option = next.option;
  }
  return option;
}

